/**
 * @summary Get overall stats for a student
 */
export const getGetProgressStatsUrl = (params?: GetProgressStatsParams) => {
  const normalizedParams = new URLSearchParams();

  Object.entries(params || {}).forEach(([key, value]) => {
    if (value !== undefined) {
      normalizedParams.append(key, value === null ? "null" : value.toString());
    }
  });

  const stringifiedParams = normalizedParams.toString();

  return stringifiedParams.length > 0
    ? `/api/progress/stats?${stringifiedParams}`
    : `/api/progress/stats`;
};

export const getProgressStats = async (
  params?: GetProgressStatsParams,
  options?: RequestInit,
): Promise<ProgressStats> => {
  return customFetch<ProgressStats>(getGetProgressStatsUrl(params), {
    ...options,
    method: "GET",
  });
};

